INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('promotion-6e2f88c7-moex-00064', 'promotion-6e2f88c7', 'promotion-6e2f88c7-moex-112-916530c6', 'sub-promotion-6e2f88c7-01', NULL, 'essay', '甲缺錢花用，想起曾在某飲料店打工，該店週日打烊後店員會將現金留
在收銀機內，等店長週一到店內收取，遂決定鋌而走險。甲知店員習慣
將鐵捲門遙控器藏在何處，故在某個週日午夜前往該店面，順利找到遙
控器、開啟鐵捲門，進入後再將鐵捲門放下。當甲正端詳著收銀機，思
考要設法撬開還是整台抱走時，聽到外面一陣警車鳴笛聲呼嘯而過。甲
雖知警車是在追緝其他車輛，應未注意到鐵捲門內的動態，但仍感到膽
戰心驚，經過一番天人交戰後，決定罷手離去。試問甲上述行為在刑法
上應如何評價？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:56+00:00", "source_pdf_sha1": "0475822c5c8f", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112170", "c": "125", "s": "0505", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "刑法", "year": "112", "exam_name": "112年公務人員升官等考試、112年關務人員升官等考試、112年交通事業鐵路人員升資考試、112年交通事業港務人員升資考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "法制"}'::jsonb, NULL),
  ('promotion-6e2f88c7-moex-00065', 'promotion-6e2f88c7', 'promotion-6e2f88c7-moex-112-916530c6', 'sub-promotion-6e2f88c7-01', NULL, 'essay', '甲任職於戶政事務所，遇民眾乙申辦英文戶籍謄本，依規定應於六個工
作天內核發，但乙再三拜託，表示後天即將出國，希望最晚隔天就要拿
到。適因天候不佳，洽公民眾少，甲評估手邊案量，告知乙 3小時後可
取件，下不為例。3 小時後，乙果然依約來取件，並帶了 6 杯珍珠奶茶
（每杯市價新臺幣 60 元），表示要慰勞甲及機關同仁的辛勞。甲原本不
肯收，但科長丙見狀，認為民眾辛苦提過來，堅辭不收未免太不近人情，
指示甲收下。試問甲上述行為是否成立刑法瀆職罪章中的何種犯罪？
（25分）
12550', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:56+00:00", "source_pdf_sha1": "0475822c5c8f", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112170", "c": "125", "s": "0505", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "刑法", "year": "112", "exam_name": "112年公務人員升官等考試、112年關務人員升官等考試、112年交通事業鐵路人員升資考試、112年交通事業港務人員升資考試", "original_question_number": "三", "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "法制"}'::jsonb, NULL),
  ('promotion-6e2f88c7-moex-00066', 'promotion-6e2f88c7', 'promotion-6e2f88c7-moex-112-916530c6', 'sub-promotion-6e2f88c7-01', NULL, 'essay', '甲為某公務機關科長，因無法出席科員 X的婚宴，將禮金新臺幣（下同）
