（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:56+00:00", "source_pdf_sha1": "0635b758199f", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112170", "c": "125", "s": "0501", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民法", "year": "112", "exam_name": "112年公務人員升官等考試、112年關務人員升官等考試、112年交通事業鐵路人員升資考試、112年交通事業港務人員升資考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "法制"}'::jsonb, NULL),
  ('promotion-6e2f88c7-moex-00068', 'promotion-6e2f88c7', 'promotion-6e2f88c7-moex-112-9b7ab1bb', 'sub-promotion-6e2f88c7-02', NULL, 'essay', '甲貨運公司所僱用的司機乙，於送貨途中闖紅燈，不慎撞死正在過馬路
的丙。丙遠在國外留學的未婚妻丁得知此消息後傷心欲絕，向乙請求慰
撫金，且由於丙生前全額負擔丁在國外之生活費，丁遂一併請求扶養費
之賠償，並依民法第 188 條規定，主張甲應負連帶賠償責任。試問丁之
