  ('promotion-6e2f88c7-moex-00069', 'promotion-6e2f88c7', 'promotion-6e2f88c7-moex-112-9b7ab1bb', 'sub-promotion-6e2f88c7-02', NULL, 'single_choice', '有限合夥之性質為何？', '["財團法人", "社團法人", "非法人團體", "無權利能力社團"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:56+00:00", "source_pdf_sha1": "0635b758199f", "answer_pdf_sha1": "cdba98d79113", "source_family": "moex-gov-tw", "moex": {"exam_code": "112170", "c": "125", "s": "0501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "112", "exam_name": "112年公務人員升官等考試、112年關務人員升官等考試、112年交通事業鐵路人員升資考試、112年交通事業港務人員升資考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "法制"}'::jsonb, NULL),
  ('promotion-6e2f88c7-moex-00070', 'promotion-6e2f88c7', 'promotion-6e2f88c7-moex-112-9b7ab1bb', 'sub-promotion-6e2f88c7-02', NULL, 'single_choice', '下列關於法律行為無效之敘述，依民法規定，何者正確？', '["法律行為之一部分無效者，僅該部分無效，其他部分，當然有效", "無效法律行為之當事人，於行為當時不知其無效，亦非可得而知者，負回復原狀或損害賠償之責任", "財團董事，有違反捐助章程之行為時，法院得因主管機關、檢察官或利害關係人之聲請，宣告其行為無效", "無效之法律行為，只要具備他法律行為之要件，不問當事人是否若知其無效，即欲為他法律行 為，均當然轉換為該他法律行為"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:56+00:00", "source_pdf_sha1": "0635b758199f", "answer_pdf_sha1": "cdba98d79113", "source_family": "moex-gov-tw", "moex": {"exam_code": "112170", "c": "125", "s": "0501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "112", "exam_name": "112年公務人員升官等考試、112年關務人員升官等考試、112年交通事業鐵路人員升資考試、112年交通事業港務人員升資考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "法制"}'::jsonb, NULL),
